INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which statement BEST describes the core idea of Infrastructure as Code (IaC)?$tf$, $tf$[{"id":"a","text":"Provisioning infrastructure by manually clicking through a cloud console and recording the steps in a wiki."},{"id":"b","text":"Defining and managing infrastructure through machine-readable configuration files that can be versioned, reviewed, and reused."},{"id":"c","text":"Running operating-system patches automatically on a fixed schedule."},{"id":"d","text":"Storing application source code in a version control system."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$IaC means infrastructure is described in declarative/configuration files that can be version-controlled and reused. Manual console clicks and OS patching are not IaC, and storing app source code alone is just source control.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which statement BEST describes the core idea of Infrastructure as Code (IaC)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A team adopts IaC and commits all Terraform configuration to Git. Which benefit is MOST directly enabled by this practice?$tf$, $tf$[{"id":"a","text":"Infrastructure changes can be peer-reviewed and rolled back like application code."},{"id":"b","text":"Terraform no longer needs to track state."},{"id":"c","text":"Cloud provider credentials are no longer required."},{"id":"d","text":"Resources are provisioned without any API calls."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Version-controlling configuration enables code review, history, and rollback of infrastructure changes. State is still required, credentials are still needed, and Terraform still calls provider APIs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A team adopts IaC and commits all Terraform configuration to Git. Which benefit is MOST directly enabled by this practice?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which characteristic distinguishes Terraform as a provisioning tool from configuration-management tools like Ansible, Chef, or Puppet?$tf$, $tf$[{"id":"a","text":"Terraform focuses on provisioning and managing the lifecycle of infrastructure resources, not on configuring software inside existing servers."},{"id":"b","text":"Terraform can only manage a single cloud provider at a time."},{"id":"c","text":"Terraform requires an agent installed on every managed machine."},{"id":"d","text":"Terraform cannot create or destroy infrastructure resources."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform is primarily a provisioning tool that manages the full lifecycle of infrastructure across many providers, while config-management tools specialize in configuring software on already-provisioned machines. Terraform is multi-cloud and agentless.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which characteristic distinguishes Terraform as a provisioning tool from configuration-management tools like Ansible, Chef, or Puppet?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why is Terraform considered "cloud-agnostic" / multi-cloud?$tf$, $tf$[{"id":"a","text":"It only works with HashiCorp Cloud Platform."},{"id":"b","text":"It uses a provider plugin model so the same workflow can manage AWS, Azure, GCP, Kubernetes, and many other platforms."},{"id":"c","text":"It translates configuration into CloudFormation under the hood."},{"id":"d","text":"It requires a different binary for each cloud provider."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Terraform uses a plugin-based provider architecture, so one consistent workflow and language manage resources across many platforms with a single binary. It does not delegate to CloudFormation.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why is Terraform considered "cloud-agnostic" / multi-cloud?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which Terraform command must be run FIRST in a new configuration directory to download provider plugins and prepare the backend?$tf$, $tf$[{"id":"a","text":"terraform plan"},{"id":"b","text":"terraform apply"},{"id":"c","text":"terraform init"},{"id":"d","text":"terraform validate"}]$tf$::jsonb, $tf$["c"]$tf$::jsonb, $tf$`terraform init` initializes the working directory: it downloads provider plugins, installs modules, and configures the backend. Plan, apply, and validate all require an initialized directory.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which Terraform command must be run FIRST in a new configuration directory to download provider plugins and prepare the backend?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$In a Terraform configuration, which block is used to declare and constrain the provider plugins a configuration depends on?$tf$, $tf$[{"id":"a","text":"The `terraform { required_providers { ... } }` block."},{"id":"b","text":"The `resource` block."},{"id":"c","text":"The `output` block."},{"id":"d","text":"The `data` block."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`required_providers` inside the `terraform` settings block declares each provider's source address and version constraints. Resource/data blocks define infrastructure and outputs expose values.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In a Terraform configuration, which block is used to declare and constrain the provider plugins a configuration depends on?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about the Terraform configuration language (HCL).$tf$, $tf$[{"id":"a","text":"HCL is declarative — you describe the desired end state, not step-by-step instructions."},{"id":"b","text":"Resources are addressed as `<resource_type>.<name>` within the configuration."},{"id":"c","text":"Terraform configuration files must use a `.tf` (or `.tf.json`) extension to be loaded."},{"id":"d","text":"Terraform executes resource blocks strictly in the order they appear in the file."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$HCL is declarative, resources are referenced as type.name, and config files use `.tf`/`.tf.json`. Terraform builds a dependency graph and does NOT rely on textual order of blocks.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language","label":"Terraform Docs — Configuration Language"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about the Terraform configuration language (HCL).$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the canonical Terraform core workflow?$tf$, $tf$[{"id":"a","text":"Write → Plan → Apply"},{"id":"b","text":"Build → Test → Deploy"},{"id":"c","text":"Init → Destroy → Apply"},{"id":"d","text":"Plan → Validate → Format"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The Terraform core workflow is Write (author config), Plan (preview changes), and Apply (execute). The other sequences are not the documented core workflow.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/tutorials/aws-get-started","label":"Terraform Tutorials — Get Started"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the canonical Terraform core workflow?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does `terraform plan` do?$tf$, $tf$[{"id":"a","text":"Permanently provisions all resources defined in the configuration."},{"id":"b","text":"Creates an execution plan describing the actions Terraform would take to reach the desired state, without changing real infrastructure."},{"id":"c","text":"Deletes all resources tracked in state."},{"id":"d","text":"Uploads the state file to a remote backend."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform plan` is a read-only preview: it compares desired config to current state and shows additions/changes/deletions without modifying infrastructure. Apply performs changes; destroy removes resources.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does `terraform plan` do?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You run `terraform apply` and Terraform prompts "Do you want to perform these actions?". Which flag would skip this interactive approval (e.g. in CI)?$tf$, $tf$[{"id":"a","text":"-auto-approve"},{"id":"b","text":"-force"},{"id":"c","text":"-no-prompt"},{"id":"d","text":"-yes"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform apply -auto-approve` skips the interactive confirmation. There is no `-force`, `-no-prompt`, or `-yes` flag for this purpose on apply.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You run `terraform apply` and Terraform prompts "Do you want to perform these actions?". Which flag would skip this interactive approval (e.g. in CI)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$In Terraform, what is a module?$tf$, $tf$[{"id":"a","text":"A container for multiple resources that are used together, callable from other configurations."},{"id":"b","text":"A single resource block."},{"id":"c","text":"A cloud provider plugin binary."},{"id":"d","text":"A state file stored in a remote backend."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A module is a reusable container of resources (and variables/outputs) that can be called from other configurations via a `module` block. It is not a single resource, a provider, or a state file.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In Terraform, what is a module?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which `module` block argument specifies WHERE the module code comes from?$tf$, $tf$[{"id":"a","text":"version"},{"id":"b","text":"source"},{"id":"c","text":"providers"},{"id":"d","text":"depends_on"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The `source` argument is mandatory and tells Terraform where to load the module (local path, registry, Git, etc.). `version` constrains registry module versions; the others have different roles.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which `module` block argument specifies WHERE the module code comes from?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A root module needs a value produced inside a child module `network` (e.g. a VPC ID). How is that value exposed and consumed?$tf$, $tf$[{"id":"a","text":"The child module declares an `output`; the root module references it as `module.network.<output_name>`."},{"id":"b","text":"The root module reads the child module's state file directly."},{"id":"c","text":"The child module declares a `variable`; the root references `var.network`."},{"id":"d","text":"Child module values are global and need no declaration."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Child modules expose values via `output` blocks, consumed by the caller as `module.<name>.<output>`. Variables are inputs INTO a module, not outputs, and module internals are otherwise encapsulated.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A root module needs a value produced inside a child module `network` (e.g. a VPC ID). How is that value exposed and consumed?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$An EC2 instance was created manually in the AWS console and you want Terraform to manage it going forward. Which command brings the existing resource under Terraform management?$tf$, $tf$[{"id":"a","text":"terraform refresh"},{"id":"b","text":"terraform import"},{"id":"c","text":"terraform apply -replace"},{"id":"d","text":"terraform state rm"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform import` associates an existing real-world resource with a Terraform resource address in state. `refresh` only updates state from reality, `-replace` recreates, and `state rm` removes tracking.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/import","label":"Terraform Docs — terraform import"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$An EC2 instance was created manually in the AWS console and you want Terraform to manage it going forward. Which command brings the existing resource under Terraform management?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which command lets you interactively evaluate Terraform expressions and inspect values such as `var.region` or function results?$tf$, $tf$[{"id":"a","text":"terraform show"},{"id":"b","text":"terraform console"},{"id":"c","text":"terraform graph"},{"id":"d","text":"terraform output"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform console` opens an interactive REPL to evaluate expressions, functions, and state data. `show` prints state/plan, `graph` emits the dependency graph, and `output` prints root output values.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/console","label":"Terraform Docs — terraform console"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command lets you interactively evaluate Terraform expressions and inspect values such as `var.region` or function results?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the primary purpose of the Terraform state file?$tf$, $tf$[{"id":"a","text":"To store provider plugin binaries."},{"id":"b","text":"To map resources defined in configuration to real-world infrastructure objects and track metadata."},{"id":"c","text":"To store the user's cloud credentials."},{"id":"d","text":"To cache the output of `terraform fmt`."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$State maps configuration to real resources and stores metadata Terraform needs to plan changes. It is not a credential store, plugin cache, or formatting cache.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the primary purpose of the Terraform state file?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why is a remote backend (e.g. S3, HCP Terraform) recommended over the default local backend for team use?$tf$, $tf$[{"id":"a","text":"It makes Terraform run faster on a laptop."},{"id":"b","text":"It provides shared state, optional state locking, and keeps sensitive state off individual workstations."},{"id":"c","text":"It removes the need for provider plugins."},{"id":"d","text":"It disables the need for `terraform init`."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Remote backends enable shared, centralized state with locking and reduce the risk of conflicting concurrent applies. They do not affect speed materially, providers, or init requirements.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why is a remote backend (e.g. S3, HCP Terraform) recommended over the default local backend for team use?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: State locking prevents two users from running operations that write to the same state at the same time, helping avoid state corruption.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. When supported by the backend, Terraform locks state during write operations so concurrent applies cannot corrupt it. Not all backends support locking, but the statement describes its purpose correctly.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: State locking prevents two users from running operations that write to the same state at the same time, helping avoid state corruption.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You want to provide a configurable instance type without hard-coding it. Which construct should you use?$tf$, $tf$[{"id":"a","text":"An input variable declared with a `variable` block, referenced as `var.instance_type`."},{"id":"b","text":"An `output` block."},{"id":"c","text":"A `provider` block alias."},{"id":"d","text":"A `terraform` settings block."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Input variables (`variable` blocks, referenced via `var.<name>`) parameterize configuration. Outputs expose values, provider aliases configure multiple provider instances, and the terraform block holds settings.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to provide a configurable instance type without hard-coding it. Which construct should you use?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which construct lets you assign a name to an expression so it can be reused multiple times within a module without re-computing it?$tf$, $tf$[{"id":"a","text":"A local value (`locals` block), referenced as `local.<name>`."},{"id":"b","text":"An input variable."},{"id":"c","text":"A data source."},{"id":"d","text":"A provisioner."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Local values defined in a `locals` block name a computed expression for reuse via `local.<name>`. Variables are external inputs, data sources read external data, and provisioners run scripts.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/locals","label":"Terraform Docs — Local Values"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which construct lets you assign a name to an expression so it can be reused multiple times within a module without re-computing it?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which of the following is a benefit of provisioning infrastructure with IaC rather than manual processes?$tf$, $tf$[{"id":"a","text":"It removes the need to authenticate to cloud providers."},{"id":"b","text":"It improves consistency and repeatability while reducing human error from manual steps."},{"id":"c","text":"It guarantees infrastructure can never be changed."},{"id":"d","text":"It eliminates the need for any state tracking."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Codifying infrastructure makes provisioning consistent and repeatable and reduces manual mistakes. It does not remove authentication, freeze infrastructure, or eliminate state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which of the following is a benefit of provisioning infrastructure with IaC rather than manual processes?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which approach BEST exemplifies "immutable infrastructure" supported by IaC?$tf$, $tf$[{"id":"a","text":"Patching running servers in place over SSH for every change."},{"id":"b","text":"Building a new image/resource for each change and replacing the old one rather than mutating it."},{"id":"c","text":"Editing configuration directly in the cloud console."},{"id":"d","text":"Keeping a single long-lived server forever and never replacing it."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Immutable infrastructure replaces resources with newly built ones instead of mutating existing servers in place, improving predictability. In-place patching and console edits are mutable, ad-hoc practices.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which approach BEST exemplifies "immutable infrastructure" supported by IaC?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 1, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Because IaC configuration is stored in version control, infrastructure changes can use the same pull-request review process as application code.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Storing IaC in version control enables code review, history, and collaboration workflows (pull requests) for infrastructure, just like application code.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Because IaC configuration is stored in version control, infrastructure changes can use the same pull-request review process as application code.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL outcomes that IaC tools like Terraform help achieve.$tf$, $tf$[{"id":"a","text":"Reproducible environments across dev, staging, and prod."},{"id":"b","text":"A documented, reviewable history of infrastructure changes."},{"id":"c","text":"The ability to preview changes before applying them."},{"id":"d","text":"Guaranteed elimination of all cloud costs."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$IaC delivers reproducibility, an auditable change history, and (with Terraform) plan previews. It does not eliminate cloud costs — you still pay for provisioned resources.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL outcomes that IaC tools like Terraform help achieve.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Terraform is described as "provider-agnostic." What does the provider plugin model primarily enable?$tf$, $tf$[{"id":"a","text":"Managing resources across many platforms with one consistent workflow and language."},{"id":"b","text":"Running Terraform without any binary installed."},{"id":"c","text":"Avoiding the need to ever declare resources."},{"id":"d","text":"Storing state only on local disk."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Providers are plugins that let Terraform manage many platforms (clouds, SaaS, Kubernetes) through one consistent HCL workflow. It does not remove the binary, resources, or state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Terraform is described as "provider-agnostic." What does the provider plugin model primarily enable?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why does Terraform build a resource dependency graph?$tf$, $tf$[{"id":"a","text":"To bill resources by dependency count."},{"id":"b","text":"To determine the correct order to create, update, or destroy resources and parallelize where safe."},{"id":"c","text":"To replace the need for a state file."},{"id":"d","text":"To encrypt the configuration."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The dependency graph lets Terraform order operations correctly and run independent changes in parallel. It does not affect billing, replace state, or encrypt config.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/resources/behavior","label":"Terraform Docs — Resource Dependencies"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why does Terraform build a resource dependency graph?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A team wants one tool to provision a load balancer in AWS, a DNS record in Cloudflare, and a database in a managed provider — all in one config. Why is Terraform well suited?$tf$, $tf$[{"id":"a","text":"It only supports AWS so it is simpler."},{"id":"b","text":"A single configuration can use multiple providers and wire their resources together with references."},{"id":"c","text":"It requires a separate state file per provider by design."},{"id":"d","text":"It cannot reference one provider's resource from another."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Terraform configurations can declare multiple providers and reference resources across them in one plan/apply, which is a core multi-cloud strength. References across providers are fully supported.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A team wants one tool to provision a load balancer in AWS, a DNS record in Cloudflare, and a database in a managed provider — all in one config. Why is Terraform well suited?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Terraform is agentless for the platforms it manages — it talks to provider APIs and does not require software pre-installed on target infrastructure.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Terraform invokes provider APIs directly and does not need an agent on managed infrastructure, unlike some configuration-management tools.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Terraform is agentless for the platforms it manages — it talks to provider APIs and does not require software pre-installed on target infrastructure.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which block type actually creates and manages an infrastructure object?$tf$, $tf$[{"id":"a","text":"resource"},{"id":"b","text":"data"},{"id":"c","text":"output"},{"id":"d","text":"variable"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A `resource` block declares an infrastructure object Terraform creates/manages. `data` reads existing objects, `output` exposes values, and `variable` declares inputs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/resources","label":"Terraform Docs — Resources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which block type actually creates and manages an infrastructure object?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Where does Terraform install provider plugins by default during `terraform init`?$tf$, $tf$[{"id":"a","text":"Into the system PATH."},{"id":"b","text":"Into the `.terraform` directory within the working directory."},{"id":"c","text":"Into the remote state backend."},{"id":"d","text":"Into the dependency lock file."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Provider plugins and modules are installed under the `.terraform` directory in the working directory during init. The lock file records selections but does not hold the binaries.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Where does Terraform install provider plugins by default during `terraform init`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which environment variable enables detailed Terraform debug logging?$tf$, $tf$[{"id":"a","text":"TF_DEBUG"},{"id":"b","text":"TF_LOG"},{"id":"c","text":"TF_VERBOSE"},{"id":"d","text":"TF_TRACE_ONLY"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Setting `TF_LOG` (e.g. to `TRACE` or `DEBUG`) enables verbose logging; `TF_LOG_PATH` writes it to a file. The other variables do not exist.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which environment variable enables detailed Terraform debug logging?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$How do you set an input variable named `region` from the command line for a single run?$tf$, $tf$[{"id":"a","text":"terraform apply -var=\"region=us-east-1\""},{"id":"b","text":"terraform apply --set region=us-east-1"},{"id":"c","text":"terraform apply -region us-east-1"},{"id":"d","text":"terraform apply region=us-east-1"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`-var="name=value"` (or `-var-file`) sets input variables on the command line. Terraform also reads `TF_VAR_region` and `*.tfvars` files; the other syntaxes are invalid.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$How do you set an input variable named `region` from the command line for a single run?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which file name is automatically loaded for variable values without any extra flag?$tf$, $tf$[{"id":"a","text":"terraform.tfvars"},{"id":"b","text":"variables.tf"},{"id":"c","text":"vars.json"},{"id":"d","text":"terraform.config"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform automatically loads `terraform.tfvars` and `*.auto.tfvars`. `variables.tf` typically declares variables (not values), and the other names are not auto-loaded.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which file name is automatically loaded for variable values without any extra flag?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL valid ways to assign a value to an input variable.$tf$, $tf$[{"id":"a","text":"A `-var` flag on the command line."},{"id":"b","text":"A `*.tfvars` / `*.auto.tfvars` file."},{"id":"c","text":"A `TF_VAR_<name>` environment variable."},{"id":"d","text":"Defining it inside an `output` block."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Variables can be set via `-var`, `.tfvars` files, and `TF_VAR_` environment variables (plus interactive prompt for root). `output` blocks expose values; they do not assign variables.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL valid ways to assign a value to an input variable.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does the `terraform { required_version = ">= 1.5.0" }` setting do?$tf$, $tf$[{"id":"a","text":"Pins the AWS provider to 1.5.0."},{"id":"b","text":"Constrains which Terraform CLI versions may run this configuration."},{"id":"c","text":"Sets the state schema version."},{"id":"d","text":"Forces a specific module version."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`required_version` constrains the Terraform CLI version allowed to run the configuration. Provider versions use `required_providers`; module versions use the module block `version`.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does the `terraform { required_version = ">= 1.5.0" }` setting do?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$In `terraform plan` output, what does a leading `+` next to a resource mean?$tf$, $tf$[{"id":"a","text":"The resource will be updated in place."},{"id":"b","text":"The resource will be created."},{"id":"c","text":"The resource will be destroyed."},{"id":"d","text":"The resource will be replaced."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$A `+` indicates creation, `~` update in place, `-` destroy, and `-/+` replacement. So `+` means Terraform will create the resource.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In `terraform plan` output, what does a leading `+` next to a resource mean?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Running `terraform apply` with no saved plan file does what?$tf$, $tf$[{"id":"a","text":"Applies immediately with no preview."},{"id":"b","text":"Generates a plan, shows it, and prompts for approval before making changes."},{"id":"c","text":"Only formats the configuration."},{"id":"d","text":"Refuses to run without `-out`."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform apply` without a plan file first runs a plan, displays it, and asks for confirmation (unless `-auto-approve`). It does not skip the preview or require `-out`.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Running `terraform apply` with no saved plan file does what?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which command would you use to remove all managed infrastructure at the end of a temporary environment's life?$tf$, $tf$[{"id":"a","text":"terraform plan"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform validate"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform destroy` tears down all resources tracked in state for the configuration. plan previews, fmt formats, and validate checks syntax.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command would you use to remove all managed infrastructure at the end of a temporary environment's life?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You ran `terraform plan -out=tfplan` and want to inspect the saved plan in human-readable form. Which command does that?$tf$, $tf$[{"id":"a","text":"terraform show tfplan"},{"id":"b","text":"terraform output tfplan"},{"id":"c","text":"terraform console tfplan"},{"id":"d","text":"terraform validate tfplan"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform show tfplan` renders a saved plan (or state) in readable form; `terraform show -json tfplan` emits JSON. The other commands do not read plan files.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You ran `terraform plan -out=tfplan` and want to inspect the saved plan in human-readable form. Which command does that?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command refreshes state and shows what would change but is guaranteed not to modify infrastructure?$tf$, $tf$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform destroy"},{"id":"d","text":"terraform import"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform plan` is read-only: it computes and displays the diff without applying changes. apply/destroy modify infra; import mutates state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command refreshes state and shows what would change but is guaranteed not to modify infrastructure?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about the core write → plan → apply workflow.$tf$, $tf$[{"id":"a","text":"`plan` does not change real infrastructure."},{"id":"b","text":"`apply` requires approval unless `-auto-approve` is given or a saved plan file is supplied."},{"id":"c","text":"A saved plan file applied with `terraform apply tfplan` is executed without an additional prompt."},{"id":"d","text":"`apply` always ignores the configuration and only reads state."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$plan is read-only; apply prompts unless auto-approved or given a saved plan; applying a saved plan skips the extra prompt. apply uses configuration plus state — it does not ignore configuration.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about the core write → plan → apply workflow.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: `terraform apply` can be run safely before `terraform init` in a brand-new configuration directory.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$False. `terraform init` must run first to install providers/modules and configure the backend; apply errors in an uninitialized directory.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: `terraform apply` can be run safely before `terraform init` in a brand-new configuration directory.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the "root module" in a Terraform configuration?$tf$, $tf$[{"id":"a","text":"The set of `.tf` files in the directory where Terraform is run."},{"id":"b","text":"The first module published to the registry."},{"id":"c","text":"The state file."},{"id":"d","text":"The provider plugin directory."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The root module is the working directory configuration where Terraform is invoked; it may call child modules. It is not the registry, state, or plugin directory.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the "root module" in a Terraform configuration?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A registry module source is written as `hashicorp/consul/aws`. What do the three parts represent?$tf$, $tf$[{"id":"a","text":"Region / account / resource."},{"id":"b","text":"Namespace / name / target provider."},{"id":"c","text":"Version / hash / source."},{"id":"d","text":"Bucket / key / region."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Public registry module addresses use `<NAMESPACE>/<NAME>/<PROVIDER>` (e.g. `hashicorp/consul/aws`). It is unrelated to regions, hashes, or buckets.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A registry module source is written as `hashicorp/consul/aws`. What do the three parts represent?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$To use a Git branch as a module source, which form is valid?$tf$, $tf$[{"id":"a","text":"source = \"git::https://example.com/vpc.git?ref=dev\""},{"id":"b","text":"source = \"branch://dev/vpc\""},{"id":"c","text":"source = \"vpc.git@dev\""},{"id":"d","text":"source = \"https://example.com/vpc#dev\""}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Git module sources use the `git::` prefix and a `?ref=` query for a branch/tag/commit. The other syntaxes are not valid Terraform module source forms.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$To use a Git branch as a module source, which form is valid?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A module is called with `count = 3`. How do you reference an output `id` of the second instance from the caller?$tf$, $tf$[{"id":"a","text":"module.thing[1].id"},{"id":"b","text":"module.thing.id[1]"},{"id":"c","text":"module.thing.1.id"},{"id":"d","text":"count.module.thing.id"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$With `count`, module instances are indexed: `module.<name>[<index>].<output>`, so the second is `module.thing[1].id`. The other forms are invalid address syntax.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/count","label":"Terraform Docs — count"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A module is called with `count = 3`. How do you reference an output `id` of the second instance from the caller?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why is pinning a registry module `version` (e.g. `version = "~> 4.0"`) considered a best practice?$tf$, $tf$[{"id":"a","text":"It makes `terraform init` skip downloading the module."},{"id":"b","text":"It prevents unexpected breaking changes by controlling which module releases are used."},{"id":"c","text":"It encrypts the module source."},{"id":"d","text":"It is required for local path modules."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Version constraints protect you from unexpected breaking updates by bounding which module releases Terraform may select. Local path modules are not versioned, and version does not skip downloads or encrypt anything.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why is pinning a registry module `version` (e.g. `version = "~> 4.0"`) considered a best practice?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about Terraform modules.$tf$, $tf$[{"id":"a","text":"Input variables pass values into a module."},{"id":"b","text":"Output values expose data from a module to its caller."},{"id":"c","text":"A module can call other (child) modules."},{"id":"d","text":"A module's internal resources are directly addressable from the caller without outputs."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Modules take inputs via variables, expose data via outputs, and can nest child modules. Internal resources are encapsulated — the caller must use outputs, not reach inside.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about Terraform modules.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which `module` block meta-argument explicitly orders a module after another resource/module is created?$tf$, $tf$[{"id":"a","text":"depends_on"},{"id":"b","text":"source"},{"id":"c","text":"version"},{"id":"d","text":"sensitive"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`depends_on` on a module block creates an explicit ordering dependency. `source`/`version` locate the module; `sensitive` is not a module-block meta-argument.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/depends_on","label":"Terraform Docs — Meta-Arguments"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which `module` block meta-argument explicitly orders a module after another resource/module is created?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command prints a human-readable representation of the current state?$tf$, $tf$[{"id":"a","text":"terraform show"},{"id":"b","text":"terraform plan -state"},{"id":"c","text":"terraform fmt -state"},{"id":"d","text":"terraform init -show"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform show` (with no arguments) renders the current state in readable form; it can also render a saved plan file. The other invocations are not valid.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command prints a human-readable representation of the current state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$When importing an existing resource, what must already exist in your configuration for `terraform import aws_instance.web i-123` to succeed?$tf$, $tf$[{"id":"a","text":"A matching `resource \"aws_instance\" \"web\"` block."},{"id":"b","text":"A saved plan file."},{"id":"c","text":"An output block named web."},{"id":"d","text":"A workspace named web."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Classic `terraform import` requires the target resource block to exist in configuration so the imported object can be bound to that address. It does not need a plan file, output, or workspace.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/import","label":"Terraform Docs — terraform import"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$When importing an existing resource, what must already exist in your configuration for `terraform import aws_instance.web i-123` to succeed?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You want a machine-readable JSON of all root outputs for a deployment pipeline. Which command?$tf$, $tf$[{"id":"a","text":"terraform output -json"},{"id":"b","text":"terraform show -outputs"},{"id":"c","text":"terraform console --json"},{"id":"d","text":"terraform state outputs"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform output -json` emits all root output values as JSON for scripting. The other forms are not valid output-retrieval commands.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/output","label":"Terraform Docs — terraform output"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want a machine-readable JSON of all root outputs for a deployment pipeline. Which command?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: `terraform state` subcommands (list, show, mv, rm) let you inspect and surgically modify state outside the normal plan/apply cycle.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. The `terraform state` family is the supported way to inspect and advanced-modify state (list/show/mv/rm) without a full plan/apply.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: `terraform state` subcommands (list, show, mv, rm) let you inspect and surgically modify state outside the normal plan/apply cycle.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the default backend Terraform uses if none is configured?$tf$, $tf$[{"id":"a","text":"The S3 backend."},{"id":"b","text":"The local backend (a `terraform.tfstate` file on disk)."},{"id":"c","text":"HCP Terraform."},{"id":"d","text":"No state is kept at all."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Without a configured backend, Terraform uses the local backend, writing `terraform.tfstate` to the working directory. State is always kept; it is just stored locally.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the default backend Terraform uses if none is configured?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command shows the attributes of a single resource recorded in state?$tf$, $tf$[{"id":"a","text":"terraform state show ADDR"},{"id":"b","text":"terraform output ADDR"},{"id":"c","text":"terraform plan ADDR"},{"id":"d","text":"terraform fmt ADDR"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform state show <address>` prints the stored attributes of one resource. `output` reads outputs, `plan` previews changes, and `fmt` formats files.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command shows the attributes of a single resource recorded in state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command creates a new CLI workspace named "staging"?$tf$, $tf$[{"id":"a","text":"terraform workspace new staging"},{"id":"b","text":"terraform workspace create staging"},{"id":"c","text":"terraform new workspace staging"},{"id":"d","text":"terraform workspace add staging"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform workspace new <name>` creates and switches to a new workspace; `terraform workspace select` switches to an existing one. The other forms are invalid.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command creates a new CLI workspace named "staging"?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Within configuration, how do you reference the name of the currently selected CLI workspace?$tf$, $tf$[{"id":"a","text":"terraform.workspace"},{"id":"b","text":"var.workspace"},{"id":"c","text":"local.workspace"},{"id":"d","text":"workspace.current"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `terraform.workspace` expression returns the current workspace name, often used to vary naming/sizing per environment. The other references are not built-in.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Within configuration, how do you reference the name of the currently selected CLI workspace?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why should the state file generally NOT be committed to a public Git repository?$tf$, $tf$[{"id":"a","text":"It is too large for Git."},{"id":"b","text":"It may contain sensitive values (secrets, IPs) and can cause conflicts/corruption with concurrent edits."},{"id":"c","text":"Git cannot store JSON."},{"id":"d","text":"Terraform refuses to read state from Git."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$State can hold secrets and is prone to merge conflicts/corruption if shared via Git; a locking remote backend is recommended instead. Size and JSON support are not the issues.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why should the state file generally NOT be committed to a public Git repository?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A backend supports locking. What is the main risk if locking were unavailable and two engineers ran `apply` simultaneously?$tf$, $tf$[{"id":"a","text":"Slightly slower applies."},{"id":"b","text":"State corruption or lost updates from concurrent writes."},{"id":"c","text":"Provider plugins would be deleted."},{"id":"d","text":"The configuration would be reformatted."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Concurrent writes to the same state without locking can corrupt it or lose updates. Locking serializes write operations to prevent this; it is unrelated to formatting or plugins.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A backend supports locking. What is the main risk if locking were unavailable and two engineers ran `apply` simultaneously?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL valid uses of the `terraform state` command family.$tf$, $tf$[{"id":"a","text":"Listing tracked resource addresses (`state list`)."},{"id":"b","text":"Moving a resource to a new address (`state mv`)."},{"id":"c","text":"Removing a resource from state without destroying it (`state rm`)."},{"id":"d","text":"Downloading provider plugins (`state init`)."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$`state list`, `state mv`, and `state rm` are real subcommands. There is no `state init`; provider plugins are installed by `terraform init`.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL valid uses of the `terraform state` command family.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You want to iterate over a map to create one resource per key with stable addresses. Which meta-argument is best?$tf$, $tf$[{"id":"a","text":"for_each"},{"id":"b","text":"count"},{"id":"c","text":"depends_on"},{"id":"d","text":"lifecycle"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`for_each` over a map/set keys instances by key, giving stable addresses when the collection changes (unlike `count`, which uses positional indexes). depends_on and lifecycle do not iterate.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to iterate over a map to create one resource per key with stable addresses. Which meta-argument is best?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which declaration prevents an output value from being shown in CLI plan/apply output?$tf$, $tf$[{"id":"a","text":"Adding `sensitive = true` to the `output` block."},{"id":"b","text":"Adding `hidden = true` to the `output` block."},{"id":"c","text":"Wrapping the value in `nonsensitive()`."},{"id":"d","text":"Setting `count = 0` on the output."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Marking an output `sensitive = true` redacts it from CLI output (it is still stored in state). `nonsensitive()` does the opposite; `hidden` and `count` on outputs are not how this works.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which declaration prevents an output value from being shown in CLI plan/apply output?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which expression accesses the `id` attribute of a resource declared as `resource "aws_vpc" "main"`?$tf$, $tf$[{"id":"a","text":"aws_vpc.main.id"},{"id":"b","text":"var.aws_vpc.main.id"},{"id":"c","text":"resource.aws_vpc.main.id"},{"id":"d","text":"module.aws_vpc.main.id"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Managed resource attributes are referenced as `<type>.<name>.<attr>` — here `aws_vpc.main.id`. The `var.`/`module.`/`resource.` prefixes are wrong for a managed resource attribute reference.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/expressions","label":"Terraform Docs — Expressions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which expression accesses the `id` attribute of a resource declared as `resource "aws_vpc" "main"`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which function returns the first non-null argument and is useful for variable defaulting?$tf$, $tf$[{"id":"a","text":"coalesce"},{"id":"b","text":"lookup"},{"id":"c","text":"flatten"},{"id":"d","text":"try"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`coalesce` returns the first non-null/non-empty argument, handy for defaults. `lookup` reads a map key, `flatten` flattens nested lists, and `try` swallows evaluation errors.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/functions","label":"Terraform Docs — Built-in Functions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which function returns the first non-null argument and is useful for variable defaulting?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: A `validation` block inside a `variable` declaration can enforce custom rules (e.g. allowed values) and fail the run with a message if violated.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Variable `validation` blocks define a `condition` and `error_message`, rejecting invalid input early with a clear message.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P1$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: A `validation` block inside a `variable` declaration can enforce custom rules (e.g. allowed values) and fail the run with a message if violated.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which of the following is an advantage of declarative IaC (like Terraform) over an imperative scripting approach?$tf$, $tf$[{"id":"a","text":"You must specify every API call in the exact order to execute."},{"id":"b","text":"You describe the desired end state and the tool determines the operations needed to reach it."},{"id":"c","text":"It cannot detect drift from the desired state."},{"id":"d","text":"It always requires an agent on the target machine."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Declarative IaC lets you state the desired end result; the engine computes the required changes and can detect drift. Imperative scripting requires ordering every step manually.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which of the following is an advantage of declarative IaC (like Terraform) over an imperative scripting approach?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Treating infrastructure as code allows the same configuration to be reliably reproduced across multiple environments (dev, staging, prod).$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Reproducibility across environments is a key IaC benefit — the same versioned configuration (parameterized by variables) recreates consistent infrastructure.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Treating infrastructure as code allows the same configuration to be reliably reproduced across multiple environments (dev, staging, prod).$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$How does Terraform state help Terraform achieve its purpose of safe, predictable changes?$tf$, $tf$[{"id":"a","text":"It stores the desired configuration so Git is unnecessary."},{"id":"b","text":"It records what Terraform manages so plans can show an accurate diff between desired config and real infrastructure."},{"id":"c","text":"It encrypts all provider API traffic."},{"id":"d","text":"It eliminates the need for provider plugins."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$State lets Terraform compare desired configuration with the last-known real infrastructure to produce an accurate execution plan. It does not replace version control, encrypt API traffic, or remove providers.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$How does Terraform state help Terraform achieve its purpose of safe, predictable changes?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL benefits Terraform provides as an infrastructure provisioning tool.$tf$, $tf$[{"id":"a","text":"A consistent workflow across many providers."},{"id":"b","text":"An execution plan that previews changes before they are applied."},{"id":"c","text":"Tracking of resource relationships via a dependency graph."},{"id":"d","text":"Automatic configuration of application software inside running VMs without any provisioner."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Terraform offers a uniform multi-provider workflow, plan previews, and graph-based dependency ordering. It does NOT inherently configure in-VM software — that is the domain of configuration-management tools (or explicit provisioners).$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL benefits Terraform provides as an infrastructure provisioning tool.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which source address format correctly identifies the official AWS provider in `required_providers`?$tf$, $tf$[{"id":"a","text":"source = \"aws\""},{"id":"b","text":"source = \"hashicorp/aws\""},{"id":"c","text":"source = \"terraform-provider-aws\""},{"id":"d","text":"source = \"registry/aws/latest\""}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Provider source addresses use `<NAMESPACE>/<TYPE>` (here `hashicorp/aws`), optionally with a host prefix. The bare name and the other forms are not valid source addresses.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which source address format correctly identifies the official AWS provider in `required_providers`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$In `version = "~> 1.2.0"` inside `required_providers`, what does the `~>` operator mean?$tf$, $tf$[{"id":"a","text":"Exactly version 1.2.0 only."},{"id":"b","text":"Allow the rightmost version component to increment — here >= 1.2.0 and < 1.3.0."},{"id":"c","text":"Any version greater than 1.2.0 with no upper bound."},{"id":"d","text":"Any version less than 1.2.0."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The pessimistic constraint `~>` allows the last specified component to increase. `~> 1.2.0` permits 1.2.x but not 1.3.0. Exact pinning uses `= 1.2.0`.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In `version = "~> 1.2.0"` inside `required_providers`, what does the `~>` operator mean?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$What is the role of the dependency lock file (`.terraform.lock.hcl`)?$tf$, $tf$[{"id":"a","text":"It stores the Terraform state."},{"id":"b","text":"It records the selected provider versions and hashes so the same versions are used on subsequent runs."},{"id":"c","text":"It locks the state during apply."},{"id":"d","text":"It contains the cloud credentials."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The lock file pins provider selections (versions + hashes) for reproducible installs across machines. It is unrelated to state storage, state locking, or credentials.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the role of the dependency lock file (`.terraform.lock.hcl`)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You want to save a plan to a file and apply exactly that plan later. Which commands do this?$tf$, $tf$[{"id":"a","text":"terraform plan -out=tfplan, then terraform apply tfplan"},{"id":"b","text":"terraform plan > tfplan, then terraform apply < tfplan"},{"id":"c","text":"terraform save tfplan, then terraform run tfplan"},{"id":"d","text":"terraform plan --export tfplan, then terraform deploy tfplan"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform plan -out=tfplan` writes a binary plan file; `terraform apply tfplan` applies exactly that saved plan with no further prompt. Shell redirection or invented flags do not work.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to save a plan to a file and apply exactly that plan later. Which commands do this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command destroys all remote objects managed by the current configuration?$tf$, $tf$[{"id":"a","text":"terraform delete"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform apply -remove"},{"id":"d","text":"terraform state rm"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform destroy` removes all infrastructure tracked in state for the configuration. `state rm` only stops tracking a resource without destroying it; the other commands do not exist.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command destroys all remote objects managed by the current configuration?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A single resource is misbehaving and you want Terraform to destroy and recreate ONLY that resource on the next apply (current recommended approach).$tf$, $tf$[{"id":"a","text":"terraform apply -replace=\"aws_instance.web\""},{"id":"b","text":"terraform taint aws_instance.web only"},{"id":"c","text":"terraform destroy -target then re-apply manually each time"},{"id":"d","text":"terraform refresh aws_instance.web"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform apply -replace=ADDR` is the current recommended way to force replacement of a specific resource. `terraform taint` is deprecated in favor of `-replace`; refresh only syncs state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/taint","label":"Terraform Docs — terraform taint"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A single resource is misbehaving and you want Terraform to destroy and recreate ONLY that resource on the next apply (current recommended approach).$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$When you reference a module from the public Terraform Registry, which arguments are typically required in the `module` block?$tf$, $tf$[{"id":"a","text":"source and (recommended) version"},{"id":"b","text":"count and for_each"},{"id":"c","text":"provider and backend"},{"id":"d","text":"depends_on and lifecycle"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Registry modules need a `source` address; specifying `version` is strongly recommended to pin a known release. The other pairs are unrelated meta-arguments/blocks.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$When you reference a module from the public Terraform Registry, which arguments are typically required in the `module` block?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$How do you pass values INTO a child module?$tf$, $tf$[{"id":"a","text":"By setting the module's declared input variables as arguments in the `module` block."},{"id":"b","text":"By editing the child module's state file."},{"id":"c","text":"Through the child module's `output` blocks."},{"id":"d","text":"Through environment variables only."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A module's input variables are set as arguments within the calling `module` block. Outputs send values back to the caller; you do not edit state to pass inputs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$How do you pass values INTO a child module?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL valid Terraform module source types.$tf$, $tf$[{"id":"a","text":"A local path such as \"./modules/network\"."},{"id":"b","text":"A Terraform Registry address such as \"terraform-aws-modules/vpc/aws\"."},{"id":"c","text":"A Git repository such as \"git::https://example.com/vpc.git\"."},{"id":"d","text":"A raw state file URL such as \"state://prod.tfstate\"."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Local paths, registry addresses, and Git (and other VCS/HTTP/bucket) sources are supported module source types. There is no `state://` module source.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL valid Terraform module source types.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command produces a visual representation (DOT graph) of the resource dependency graph?$tf$, $tf$[{"id":"a","text":"terraform graph"},{"id":"b","text":"terraform show -graph"},{"id":"c","text":"terraform plan -graph"},{"id":"d","text":"terraform console -graph"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform graph` outputs the dependency graph in DOT format for visualization. The other commands do not have a `-graph` mode.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command produces a visual representation (DOT graph) of the resource dependency graph?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You suspect the real infrastructure has drifted from state (someone changed a resource manually). Which command updates state to match real-world resources without modifying infrastructure?$tf$, $tf$[{"id":"a","text":"terraform apply -refresh-only"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform import"},{"id":"d","text":"terraform fmt"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform apply -refresh-only` reconciles state with the actual remote objects without changing infrastructure. Import adds a new resource to state; destroy removes infra; fmt only formats files.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You suspect the real infrastructure has drifted from state (someone changed a resource manually). Which command updates state to match real-world resources without modifying infrastructure?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command lists all resource addresses currently tracked in the Terraform state?$tf$, $tf$[{"id":"a","text":"terraform state list"},{"id":"b","text":"terraform show list"},{"id":"c","text":"terraform list state"},{"id":"d","text":"terraform get state"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform state list` prints the resource addresses in state. The other forms are not valid Terraform subcommands.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command lists all resource addresses currently tracked in the Terraform state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A resource was removed from configuration but you want Terraform to STOP managing it WITHOUT destroying the real resource. Which command achieves this?$tf$, $tf$[{"id":"a","text":"terraform destroy -target=ADDR"},{"id":"b","text":"terraform state rm ADDR"},{"id":"c","text":"terraform taint ADDR"},{"id":"d","text":"terraform apply -replace=ADDR"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform state rm` removes the resource from state so Terraform no longer manages it, leaving the real object intact. Destroy deletes it; taint/replace force recreation.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A resource was removed from configuration but you want Terraform to STOP managing it WITHOUT destroying the real resource. Which command achieves this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$When using an S3 remote backend, which additional mechanism is commonly configured to provide state locking?$tf$, $tf$[{"id":"a","text":"A DynamoDB table (or S3-native locking) referenced by the backend configuration."},{"id":"b","text":"A second S3 bucket for backups only."},{"id":"c","text":"An EC2 instance acting as a lock server."},{"id":"d","text":"A local file on each engineer's laptop."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The S3 backend traditionally uses a DynamoDB table (newer versions also support S3-native lockfiles) to coordinate state locking and prevent concurrent writes. A backup bucket or local file does not provide locking.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$When using an S3 remote backend, which additional mechanism is commonly configured to provide state locking?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You need to read attributes of an EXISTING resource that Terraform does not manage (e.g. an existing AMI) for use in configuration. Which construct fits?$tf$, $tf$[{"id":"a","text":"A `data` source block."},{"id":"b","text":"A `resource` block."},{"id":"c","text":"An `output` block."},{"id":"d","text":"A `provisioner` block."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Data sources let configuration read information about existing/external objects without managing them. Resource blocks create/manage objects; outputs export values; provisioners run scripts.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/data-sources","label":"Terraform Docs — Data Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You need to read attributes of an EXISTING resource that Terraform does not manage (e.g. an existing AMI) for use in configuration. Which construct fits?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which built-in function would you use to join a list of strings into a single string with a comma separator?$tf$, $tf$[{"id":"a","text":"concat(\",\", list)"},{"id":"b","text":"join(\",\", list)"},{"id":"c","text":"merge(\",\", list)"},{"id":"d","text":"format(\",\", list)"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`join(separator, list)` concatenates list elements into a string using the separator. `concat` joins lists into a list, `merge` combines maps, and `format` does printf-style formatting.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/functions","label":"Terraform Docs — Built-in Functions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which built-in function would you use to join a list of strings into a single string with a comma separator?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which of the following is NOT a goal of Infrastructure as Code?$tf$, $tf$[{"id":"a","text":"Reproducible, automated provisioning."},{"id":"b","text":"Version-controlled, reviewable infrastructure changes."},{"id":"c","text":"Ad-hoc, undocumented manual changes directly in the cloud console."},{"id":"d","text":"Consistent environments across dev, staging, and prod."}]$tf$::jsonb, $tf$["c"]$tf$::jsonb, $tf$Ad-hoc, undocumented manual console changes are exactly what IaC seeks to eliminate. Reproducibility, versioning, and environment consistency are core IaC goals.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which of the following is NOT a goal of Infrastructure as Code?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A company uses IaC and wants to know exactly what changed and who approved it for an audit. Which IaC practice provides this?$tf$, $tf$[{"id":"a","text":"Storing configuration in version control with peer-reviewed pull requests."},{"id":"b","text":"Editing resources by hand and emailing screenshots."},{"id":"c","text":"Disabling state to avoid records."},{"id":"d","text":"Granting everyone console admin rights."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Versioned configuration plus reviewed pull requests yields a clear, attributable audit trail of infrastructure changes. The other options remove or undermine traceability.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A company uses IaC and wants to know exactly what changed and who approved it for an audit. Which IaC practice provides this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$How does IaC help with disaster recovery?$tf$, $tf$[{"id":"a","text":"It backs up running VM disks automatically."},{"id":"b","text":"The codified configuration can recreate infrastructure consistently in a new region or account."},{"id":"c","text":"It prevents all outages from ever happening."},{"id":"d","text":"It stores customer data redundantly."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Because infrastructure is codified, the same configuration can rebuild environments reliably elsewhere, aiding disaster recovery. IaC does not back up disks or guarantee zero outages.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$How does IaC help with disaster recovery?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: With declarative IaC you specify the desired end state and the tool figures out the operations required to reach it.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Declarative IaC tools like Terraform take a desired-state description and compute the create/update/delete actions needed to converge to it.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: With declarative IaC you specify the desired end state and the tool figures out the operations required to reach it.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which is a primary reason teams choose Terraform over writing custom cloud SDK scripts?$tf$, $tf$[{"id":"a","text":"Terraform tracks state and produces a reviewable plan, removing the need to hand-code create/update/delete logic."},{"id":"b","text":"Terraform requires no provider credentials."},{"id":"c","text":"Terraform is the only tool that can call cloud APIs."},{"id":"d","text":"Terraform forbids the use of variables."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform manages state and computes plans automatically, sparing teams from hand-writing idempotent create/update/delete logic. It still needs credentials and supports variables.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which is a primary reason teams choose Terraform over writing custom cloud SDK scripts?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$What problem does Terraform's execution plan specifically solve?$tf$, $tf$[{"id":"a","text":"It encrypts the state file at rest."},{"id":"b","text":"It lets you review proposed changes before they are applied, reducing surprise destructive actions."},{"id":"c","text":"It installs provider plugins."},{"id":"d","text":"It rotates cloud credentials."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The plan previews exactly what will be created, changed, or destroyed so risky actions can be caught before apply. Plugin install and credential handling are separate concerns.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What problem does Terraform's execution plan specifically solve?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Compared with click-ops in a console, what does Terraform add for repeatable infrastructure?$tf$, $tf$[{"id":"a","text":"A codified, versionable definition plus a consistent plan/apply workflow."},{"id":"b","text":"Free cloud compute."},{"id":"c","text":"Automatic application code deployment."},{"id":"d","text":"Elimination of the need for any cloud account."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform turns infrastructure into versioned code with a consistent workflow, unlike manual console operations. It does not provide free compute or deploy application code by itself.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"},{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Compared with click-ops in a console, what does Terraform add for repeatable infrastructure?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL statements that correctly describe Terraform's purpose and design.$tf$, $tf$[{"id":"a","text":"It is primarily an infrastructure provisioning tool."},{"id":"b","text":"It uses providers to support many platforms."},{"id":"c","text":"It produces an execution plan before changing infrastructure."},{"id":"d","text":"It is mainly a configuration-management tool for installing software inside servers."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Terraform is a provisioning tool that uses providers and produces a plan before applying. In-server software configuration is the domain of config-management tools.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"},{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL statements that correctly describe Terraform's purpose and design.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command would you run after adding a new provider to `required_providers` so it is downloaded?$tf$, $tf$[{"id":"a","text":"terraform init"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform output"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Adding or changing required providers requires re-running `terraform init` to install them. plan/fmt/output do not install providers.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command would you run after adding a new provider to `required_providers` so it is downloaded?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does `terraform init -upgrade` do?$tf$, $tf$[{"id":"a","text":"Upgrades the Terraform CLI binary."},{"id":"b","text":"Allows providers/modules to be upgraded to the newest versions allowed by constraints, updating the lock file."},{"id":"c","text":"Upgrades the remote state schema."},{"id":"d","text":"Reinstalls the operating system packages."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform init -upgrade` re-selects the newest provider/module versions permitted by constraints and updates `.terraform.lock.hcl`. It does not upgrade the CLI itself.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does `terraform init -upgrade` do?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Precedence: a variable `region` is set by a `terraform.tfvars` file AND by a `-var` flag on the command line. Which value wins?$tf$, $tf$[{"id":"a","text":"The `.tfvars` file value."},{"id":"b","text":"The `-var` command-line value."},{"id":"c","text":"Terraform errors on conflict."},{"id":"d","text":"The environment variable always wins."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Command-line `-var`/`-var-file` flags have higher precedence than `.tfvars`/`.auto.tfvars` files and `TF_VAR_` environment variables, so the `-var` value wins.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Precedence: a variable `region` is set by a `terraform.tfvars` file AND by a `-var` flag on the command line. Which value wins?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which type constraint declares a variable that must be a map of strings?$tf$, $tf$[{"id":"a","text":"type = map(string)"},{"id":"b","text":"type = list(string)"},{"id":"c","text":"type = string(map)"},{"id":"d","text":"type = object"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`map(string)` constrains the variable to a map whose values are strings. `list(string)` is a list, and the other forms are not valid type syntax.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which type constraint declares a variable that must be a map of strings?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which block configures authentication and endpoints for a platform such as AWS?$tf$, $tf$[{"id":"a","text":"The `provider` block."},{"id":"b","text":"The `output` block."},{"id":"c","text":"The `variable` block."},{"id":"d","text":"The `locals` block."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `provider` block configures provider-specific settings like region/credentials/endpoints. outputs expose values, variables declare inputs, locals name expressions.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which block configures authentication and endpoints for a platform such as AWS?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about the `terraform` settings block.$tf$, $tf$[{"id":"a","text":"It can declare `required_version` for the CLI."},{"id":"b","text":"It can declare `required_providers` with source and version."},{"id":"c","text":"It can declare a `backend` for state storage."},{"id":"d","text":"It is where you define resources to create."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$The `terraform` block holds `required_version`, `required_providers`, and `backend` settings. Resources are declared in `resource` blocks, not the terraform block.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about the `terraform` settings block.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Terraform automatically loads every file ending in `.tf` in the working directory regardless of file name.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Terraform loads all `.tf` (and `.tf.json`) files in the directory; the split into main.tf/variables.tf/outputs.tf is convention, not a requirement.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language","label":"Terraform Docs — Configuration Language"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Terraform automatically loads every file ending in `.tf` in the working directory regardless of file name.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$In plan output, what does a `~` prefix on a resource mean?$tf$, $tf$[{"id":"a","text":"Create"},{"id":"b","text":"Update in place"},{"id":"c","text":"Destroy"},{"id":"d","text":"No change"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`~` indicates an in-place update; `+` is create, `-` is destroy, and `-/+` is replacement. Unchanged resources are not listed by default.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In plan output, what does a `~` prefix on a resource mean?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What is the recommended way to skip the approval prompt during automated `terraform destroy` in CI?$tf$, $tf$[{"id":"a","text":"terraform destroy -auto-approve"},{"id":"b","text":"terraform destroy -force"},{"id":"c","text":"terraform destroy -y"},{"id":"d","text":"terraform destroy --no-confirm"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`-auto-approve` skips the interactive confirmation for both apply and destroy. The legacy `-force` flag was removed; `-y`/`--no-confirm` do not exist.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the recommended way to skip the approval prompt during automated `terraform destroy` in CI?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want plan/apply to refresh state from real infrastructure but you are confident nothing drifted and want a faster run. Which flag skips the refresh?$tf$, $tf$[{"id":"a","text":"terraform plan -refresh=false"},{"id":"b","text":"terraform plan -no-state"},{"id":"c","text":"terraform plan -skip"},{"id":"d","text":"terraform plan -fast"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`-refresh=false` tells Terraform to skip the state refresh against real resources. The other flags are not valid Terraform options.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want plan/apply to refresh state from real infrastructure but you are confident nothing drifted and want a faster run. Which flag skips the refresh?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which is the FIRST step in the Terraform core workflow?$tf$, $tf$[{"id":"a","text":"Write the configuration."},{"id":"b","text":"Apply the configuration."},{"id":"c","text":"Destroy the configuration."},{"id":"d","text":"Import existing resources."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The core workflow is Write → Plan → Apply, so authoring (writing) the configuration comes first. Apply/destroy/import come later or are outside the core loop.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/tutorials/aws-get-started","label":"Terraform Tutorials — Get Started"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which is the FIRST step in the Terraform core workflow?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A teammate asks how to see proposed changes without risk of modifying anything. What do you tell them to run?$tf$, $tf$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform plan"},{"id":"c","text":"terraform destroy"},{"id":"d","text":"terraform state rm"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`terraform plan` previews changes read-only. apply and destroy mutate infrastructure; `state rm` mutates state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A teammate asks how to see proposed changes without risk of modifying anything. What do you tell them to run?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$After `terraform apply tfplan` using a previously saved plan, why is there no second confirmation prompt?$tf$, $tf$[{"id":"a","text":"Saved plan files are encrypted."},{"id":"b","text":"A saved plan already represents an approved set of actions, so Terraform executes it directly."},{"id":"c","text":"`-auto-approve` is always implied by `init`."},{"id":"d","text":"Plan files disable all output."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Applying a saved plan executes exactly the previously reviewed actions, so no further approval is requested. This is unrelated to encryption or init.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$After `terraform apply tfplan` using a previously saved plan, why is there no second confirmation prompt?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$MULTI$tf$::"QType", $tf$Select ALL commands that can change real infrastructure.$tf$, $tf$[{"id":"a","text":"terraform apply"},{"id":"b","text":"terraform destroy"},{"id":"c","text":"terraform plan"},{"id":"d","text":"terraform validate"}]$tf$::jsonb, $tf$["a","b"]$tf$::jsonb, $tf$apply and destroy mutate real infrastructure. plan only previews and validate only checks configuration syntax/consistency.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"},{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL commands that can change real infrastructure.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which statement about module input variables is correct?$tf$, $tf$[{"id":"a","text":"They are declared in the child module and assigned by the calling module block."},{"id":"b","text":"They are declared in the calling module and read by the child via output."},{"id":"c","text":"They are global and require no declaration."},{"id":"d","text":"They are stored in the state file as the only way to pass values."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A child module declares its inputs with `variable` blocks; the caller supplies values as arguments in the `module` block. Outputs flow data back to the caller.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which statement about module input variables is correct?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the main motivation for using modules?$tf$, $tf$[{"id":"a","text":"To encrypt configuration."},{"id":"b","text":"To package and reuse a set of resources with a clean input/output interface (DRY)."},{"id":"c","text":"To avoid using providers."},{"id":"d","text":"To bypass the need for state."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Modules promote reuse and abstraction by bundling related resources behind a defined interface (inputs/outputs), keeping configuration DRY. They do not replace providers or state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the main motivation for using modules?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A local module is referenced with `source = "../modules/vpc"`. What is true of local path sources?$tf$, $tf$[{"id":"a","text":"They are not versioned; they track whatever is at that path."},{"id":"b","text":"They require a `version` argument."},{"id":"c","text":"They are downloaded from the registry."},{"id":"d","text":"They must use the `git::` prefix."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Local path modules are not versioned — Terraform uses the code at that relative path directly. The `version` argument applies only to registry modules.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A local module is referenced with `source = "../modules/vpc"`. What is true of local path sources?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A module is called with `for_each = toset(["a","b"])`. How is the "b" instance's output `arn` referenced from the caller?$tf$, $tf$[{"id":"a","text":"module.thing[\"b\"].arn"},{"id":"b","text":"module.thing.b.arn"},{"id":"c","text":"module.thing[1].arn"},{"id":"d","text":"module.thing.arn[\"b\"]"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$With `for_each`, instances are keyed by the set/map key: `module.<name>["<key>"].<output>`, so `module.thing["b"].arn`. Numeric indexing is for `count`, not `for_each`.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A module is called with `for_each = toset(["a","b"])`. How is the "b" instance's output `arn` referenced from the caller?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Where can you discover community and verified modules to reuse?$tf$, $tf$[{"id":"a","text":"The Terraform Registry (registry.terraform.io)."},{"id":"b","text":"The local backend."},{"id":"c","text":"The state file."},{"id":"d","text":"The `.terraform.lock.hcl` file."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The public Terraform Registry hosts published (including verified) modules and providers for reuse. State, backends, and the lock file are unrelated to module discovery.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Where can you discover community and verified modules to reuse?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Adding or changing a `module` block requires running `terraform init` (or `terraform get`) before the next plan.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. New or changed module sources must be installed via `terraform init` (or `terraform get`) before Terraform can plan with them.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Adding or changing a `module` block requires running `terraform init` (or `terraform get`) before the next plan.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$MULTI$tf$::"QType", $tf$Select ALL valid module `source` values.$tf$, $tf$[{"id":"a","text":"\"./modules/app\""},{"id":"b","text":"\"terraform-aws-modules/vpc/aws\""},{"id":"c","text":"\"git::https://github.com/org/repo.git//subdir?ref=v1.0.0\""},{"id":"d","text":"\"backend://prod\""}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Local paths, registry addresses, and Git URLs (including subdir and ref) are valid module sources. There is no `backend://` source scheme.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/sources","label":"Terraform Docs — Module Sources"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL valid module `source` values.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command opens an interactive REPL to test expressions against current state?$tf$, $tf$[{"id":"a","text":"terraform console"},{"id":"b","text":"terraform shell"},{"id":"c","text":"terraform repl"},{"id":"d","text":"terraform eval"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform console` is the interactive expression evaluator. `shell`, `repl`, and `eval` are not Terraform subcommands.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/console","label":"Terraform Docs — terraform console"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command opens an interactive REPL to test expressions against current state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You need read-only access to another team's VPC ID that they expose as a Terraform output in their own state. Best approach?$tf$, $tf$[{"id":"a","text":"Use the `terraform_remote_state` data source pointed at their backend."},{"id":"b","text":"Copy their `.tfstate` into your repo."},{"id":"c","text":"Hardcode the VPC ID as a string."},{"id":"d","text":"Run `terraform import` on their VPC."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `terraform_remote_state` data source reads exported outputs from another configuration's state safely (read-only). Copying state or hardcoding is fragile; import would take over management.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/remote-state-data","label":"Terraform Docs — terraform_remote_state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You need read-only access to another team's VPC ID that they expose as a Terraform output in their own state. Best approach?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command emits the dependency graph for use with a visualization tool like Graphviz?$tf$, $tf$[{"id":"a","text":"terraform graph"},{"id":"b","text":"terraform show -dot"},{"id":"c","text":"terraform plan -dot"},{"id":"d","text":"terraform draw"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform graph` outputs DOT-format graph data you can render with Graphviz. The other forms are not valid commands.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands","label":"Terraform Docs — CLI Commands"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command emits the dependency graph for use with a visualization tool like Graphviz?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want to retrieve only the value of a single root output named `endpoint` for a shell script. Which command?$tf$, $tf$[{"id":"a","text":"terraform output -raw endpoint"},{"id":"b","text":"terraform show endpoint"},{"id":"c","text":"terraform get endpoint"},{"id":"d","text":"terraform console endpoint"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform output -raw endpoint` prints just the string value of that output, ideal for scripting. `show`/`get`/`console` do not retrieve a single output that way.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/output","label":"Terraform Docs — terraform output"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to retrieve only the value of a single root output named `endpoint` for a shell script. Which command?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What is the default local state file name?$tf$, $tf$[{"id":"a","text":"state.json"},{"id":"b","text":"terraform.tfstate"},{"id":"c","text":"tfstate.lock"},{"id":"d","text":".terraform"}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$The local backend writes `terraform.tfstate` (with a `terraform.tfstate.backup` previous copy). `.terraform` is the plugin/module directory, not state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is the default local state file name?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command switches the active workspace to an existing one named "prod"?$tf$, $tf$[{"id":"a","text":"terraform workspace select prod"},{"id":"b","text":"terraform workspace new prod"},{"id":"c","text":"terraform workspace switch prod"},{"id":"d","text":"terraform select workspace prod"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform workspace select <name>` switches to an existing workspace; `new` would create one. `switch` and the last form are not valid.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command switches the active workspace to an existing one named "prod"?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A backend block is added for the first time to a config that already has local state. What does `terraform init` offer?$tf$, $tf$[{"id":"a","text":"To migrate the existing local state into the new backend."},{"id":"b","text":"To delete the local state silently."},{"id":"c","text":"To ignore the backend until next apply."},{"id":"d","text":"Nothing — backends cannot be added later."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$When a backend is added/changed, `terraform init` prompts to migrate existing state into the new backend. Backends can be added later; state is not silently deleted.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A backend block is added for the first time to a config that already has local state. What does `terraform init` offer?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which backend is purpose-built to provide managed remote state, remote runs, and locking as a service?$tf$, $tf$[{"id":"a","text":"The local backend."},{"id":"b","text":"HCP Terraform (Terraform Cloud) / `cloud` block."},{"id":"c","text":"The `terraform.tfvars` file."},{"id":"d","text":"The `.terraform` directory."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$HCP Terraform (configured via the `cloud` block or `remote` backend) provides managed state, remote operations, and locking. The local backend stores state on disk only.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/cloud","label":"Terraform Docs — HCP Terraform"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which backend is purpose-built to provide managed remote state, remote runs, and locking as a service?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Two engineers share an S3 backend with a DynamoDB lock table. Engineer A is mid-apply. What happens when Engineer B runs apply?$tf$, $tf$[{"id":"a","text":"B's apply proceeds in parallel, risking corruption."},{"id":"b","text":"B is blocked/errors with a state lock until A's operation completes."},{"id":"c","text":"B overwrites A's state immediately."},{"id":"d","text":"B's apply is queued for one hour automatically."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$With locking, B cannot acquire the state lock while A holds it, so B's operation fails fast or waits rather than corrupting state. There is no automatic one-hour queue.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Two engineers share an S3 backend with a DynamoDB lock table. Engineer A is mid-apply. What happens when Engineer B runs apply?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Each Terraform CLI workspace maintains its own distinct state while sharing the same configuration and backend.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Workspaces give multiple isolated states for one configuration/backend, enabling parallel environments without copying code.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Each Terraform CLI workspace maintains its own distinct state while sharing the same configuration and backend.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You accidentally deleted a resource from configuration and ran apply, destroying it, but want it back without recreating from scratch — what would have prevented this destroy?$tf$, $tf$[{"id":"a","text":"A `lifecycle { prevent_destroy = true }` on the resource."},{"id":"b","text":"Setting `sensitive = true` on an output."},{"id":"c","text":"Adding `depends_on`."},{"id":"d","text":"Running `terraform fmt` first."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`prevent_destroy = true` makes Terraform reject any plan that would destroy that resource, guarding critical infrastructure. The other options do not block destruction.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/lifecycle","label":"Terraform Docs — lifecycle"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You accidentally deleted a resource from configuration and ran apply, destroying it, but want it back without recreating from scratch — what would have prevented this destroy?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which expression accesses a value from a map variable `tags` at key "Name"?$tf$, $tf$[{"id":"a","text":"var.tags[\"Name\"]"},{"id":"b","text":"var.tags.Name()"},{"id":"c","text":"tags::Name"},{"id":"d","text":"var[Name].tags"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Map values are read with bracket (or dot) syntax: `var.tags["Name"]`. The other forms are not valid HCL expressions.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/expressions","label":"Terraform Docs — Expressions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which expression accesses a value from a map variable `tags` at key "Name"?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which construct best avoids repeating the same complex expression in several places within one module?$tf$, $tf$[{"id":"a","text":"A `locals` value referenced as `local.<name>`."},{"id":"b","text":"A `provisioner`."},{"id":"c","text":"A second `provider` block."},{"id":"d","text":"A `backend` block."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Local values name a computed expression once and reuse it via `local.<name>`, keeping configuration DRY. Provisioners, providers, and backends serve different purposes.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/locals","label":"Terraform Docs — Local Values"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which construct best avoids repeating the same complex expression in several places within one module?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which interpolation correctly embeds a variable into a string?$tf$, $tf$[{"id":"a","text":"\"web-${var.env}\""},{"id":"b","text":"\"web-$var.env\""},{"id":"c","text":"\"web-{{var.env}}\""},{"id":"d","text":"\"web-#var.env#\""}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$HCL string interpolation uses `${ ... }`, e.g. `"web-${var.env}"`. The other syntaxes are not valid Terraform interpolation.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/expressions","label":"Terraform Docs — Expressions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which interpolation correctly embeds a variable into a string?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want to transform a list of names into a map keyed by name. Which expression style does this?$tf$, $tf$[{"id":"a","text":"A `for` expression producing a map: `{ for n in var.names : n => upper(n) }`."},{"id":"b","text":"A `count` meta-argument."},{"id":"c","text":"A `provisioner` block."},{"id":"d","text":"A `terraform_remote_state` data source."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A `for` expression with `key => value` syntax builds a map from a collection. count multiplies resources, provisioners run scripts, and remote_state reads other state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/expressions","label":"Terraform Docs — Expressions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to transform a list of names into a map keyed by name. Which expression style does this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Marking an input variable `sensitive = true` causes Terraform to redact its value from plan/apply CLI output.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. A `sensitive` variable (or output) is redacted in CLI output, though its value is still stored in state and used during operations.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P2$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Marking an input variable `sensitive = true` causes Terraform to redact its value from plan/apply CLI output.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What is "configuration drift" in the context of IaC?$tf$, $tf$[{"id":"a","text":"When the Terraform binary version differs from the provider version."},{"id":"b","text":"When the real infrastructure no longer matches the state/configuration because of out-of-band changes."},{"id":"c","text":"When two modules use the same variable name."},{"id":"d","text":"When the plan output is longer than the apply output."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Drift is when actual infrastructure diverges from what Terraform expects (recorded in state/config), usually due to manual changes. Version mismatches and naming overlaps are different concerns.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What is "configuration drift" in the context of IaC?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which practice is MOST aligned with the IaC principle of idempotence?$tf$, $tf$[{"id":"a","text":"Re-applying the same configuration repeatedly results in the same end state with no unintended changes."},{"id":"b","text":"Each apply creates brand-new duplicate resources."},{"id":"c","text":"Manual hotfixes are applied directly in the console."},{"id":"d","text":"Configuration files are deleted after every apply."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Idempotence means applying the same desired-state configuration repeatedly converges to the same result without spurious changes. Duplicating resources or manual hotfixes break that property.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which practice is MOST aligned with the IaC principle of idempotence?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which scenario is a strong use case for Terraform specifically (rather than a config-management tool)?$tf$, $tf$[{"id":"a","text":"Installing and patching nginx inside 500 already-running servers."},{"id":"b","text":"Provisioning a multi-cloud landing zone: VPCs, subnets, load balancers, and managed databases."},{"id":"c","text":"Tailing application logs in real time."},{"id":"d","text":"Running unit tests for an application."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Provisioning and wiring cloud infrastructure across providers is Terraform's core use case. In-server software install/patching is configuration management; logging and unit tests are unrelated.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which scenario is a strong use case for Terraform specifically (rather than a config-management tool)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$HCP Terraform / Terraform Cloud adds which capability beyond the open-source CLI for the purpose of safe team collaboration?$tf$, $tf$[{"id":"a","text":"Remote state storage with remote runs, access controls, and a private module registry."},{"id":"b","text":"The ability to write configuration in HCL."},{"id":"c","text":"Support for the `terraform plan` command."},{"id":"d","text":"The provider plugin architecture."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$HCP Terraform adds managed remote state, remote operations, RBAC, policy, and a private registry for team workflows. HCL, `plan`, and the provider model are part of the open-source CLI itself.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/cloud","label":"Terraform Docs — HCP Terraform"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$HCP Terraform / Terraform Cloud adds which capability beyond the open-source CLI for the purpose of safe team collaboration?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command rewrites Terraform configuration files to the canonical HCL style/format?$tf$, $tf$[{"id":"a","text":"terraform fmt"},{"id":"b","text":"terraform style"},{"id":"c","text":"terraform lint"},{"id":"d","text":"terraform validate"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform fmt` rewrites `.tf` files to the canonical format. `terraform validate` checks syntax/consistency but does not reformat; `style` and `lint` are not Terraform subcommands.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/fmt","label":"Terraform Docs — terraform fmt"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command rewrites Terraform configuration files to the canonical HCL style/format?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does `terraform validate` check?$tf$, $tf$[{"id":"a","text":"Whether the configuration is syntactically valid and internally consistent, without contacting any provider/remote API."},{"id":"b","text":"Whether the real cloud resources still exist."},{"id":"c","text":"Whether the state file is locked."},{"id":"d","text":"Whether your cloud credentials are valid."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform validate` checks configuration syntax and internal consistency in an initialized directory; it does not access remote state, real resources, or credentials.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/validate","label":"Terraform Docs — terraform validate"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does `terraform validate` check?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You configure two instances of the AWS provider for different regions. Which feature lets a resource choose the non-default provider instance?$tf$, $tf$[{"id":"a","text":"Provider `alias` plus the resource's `provider` meta-argument (e.g. provider = aws.west)."},{"id":"b","text":"A separate backend block per region."},{"id":"c","text":"Two `terraform` settings blocks."},{"id":"d","text":"The `count` meta-argument."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Multiple provider configurations use `alias`; a resource selects one via the `provider = <name>.<alias>` meta-argument. Backends and the terraform block are unrelated; count just multiplies instances.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You configure two instances of the AWS provider for different regions. Which feature lets a resource choose the non-default provider instance?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$During `terraform plan`, a resource shows the symbol `-/+`. What does this indicate?$tf$, $tf$[{"id":"a","text":"The resource will be created only."},{"id":"b","text":"The resource will be destroyed and then re-created (replacement)."},{"id":"c","text":"The resource will be left unchanged."},{"id":"d","text":"The resource will be imported."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$In plan output, `-/+` means destroy then create (replacement). `+` is create, `~` is update in place, `-` is destroy, and unchanged resources are not shown.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$During `terraform plan`, a resource shows the symbol `-/+`. What does this indicate?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You changed only one resource and want to limit the plan/apply to that resource (use sparingly). Which flag does this?$tf$, $tf$[{"id":"a","text":"-target=\"aws_instance.web\""},{"id":"b","text":"-only=\"aws_instance.web\""},{"id":"c","text":"-resource=\"aws_instance.web\""},{"id":"d","text":"-scope=\"aws_instance.web\""}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `-target=ADDR` flag restricts operations to the specified resource (and its dependencies). It is intended for exceptional use. The other flags do not exist.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You changed only one resource and want to limit the plan/apply to that resource (use sparingly). Which flag does this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$After editing `backend` configuration in the `terraform` block, what must you do before plan/apply works again?$tf$, $tf$[{"id":"a","text":"Run `terraform init` (Terraform will prompt to migrate/reconfigure the backend)."},{"id":"b","text":"Run `terraform fmt`."},{"id":"c","text":"Delete the state file manually."},{"id":"d","text":"Nothing — backend changes take effect automatically."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Backend changes require re-running `terraform init`, which prompts to migrate or reconfigure state. Backend changes are NOT picked up automatically, and deleting state is unsafe.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$After editing `backend` configuration in the `terraform` block, what must you do before plan/apply works again?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$After adding a new `module` block that sources a registry module, which command must you run before `plan`?$tf$, $tf$[{"id":"a","text":"terraform get or terraform init (to install the module)."},{"id":"b","text":"terraform fmt"},{"id":"c","text":"terraform console"},{"id":"d","text":"terraform output"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$New/changed modules must be installed via `terraform init` (or `terraform get`) before planning. fmt, console, and output do not install modules.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$After adding a new `module` block that sources a registry module, which command must you run before `plan`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A child module declares `variable "name" {}` with no default. What happens if the calling `module` block does not set `name`?$tf$, $tf$[{"id":"a","text":"Terraform uses an empty string automatically."},{"id":"b","text":"Terraform errors because a required input variable is not set."},{"id":"c","text":"Terraform ignores the variable."},{"id":"d","text":"Terraform prompts for it only during destroy."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$A variable with no `default` is required; omitting it for a child module causes an error (child module variables cannot be supplied interactively). A missing default does not become an empty string.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A child module declares `variable "name" {}` with no default. What happens if the calling `module` block does not set `name`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want to deploy three near-identical environments from one module. Which meta-argument on the `module` block creates multiple instances keyed by a map?$tf$, $tf$[{"id":"a","text":"for_each"},{"id":"b","text":"depends_on"},{"id":"c","text":"provider"},{"id":"d","text":"lifecycle"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`for_each` on a module block instantiates the module once per map/set element, keyed by the element key. `depends_on` only orders, `provider` passes providers, and `lifecycle` is not a module-block meta-argument.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to deploy three near-identical environments from one module. Which meta-argument on the `module` block creates multiple instances keyed by a map?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command prints the values of the root module's output variables from current state?$tf$, $tf$[{"id":"a","text":"terraform output"},{"id":"b","text":"terraform show outputs"},{"id":"c","text":"terraform console -output"},{"id":"d","text":"terraform get output"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform output` reads root output values from state and can emit a specific one or JSON. The other invocations are not valid commands for this purpose.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/output","label":"Terraform Docs — terraform output"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command prints the values of the root module's output variables from current state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$One configuration needs to consume outputs produced by ANOTHER configuration's remote state. Which data source enables this?$tf$, $tf$[{"id":"a","text":"data \"terraform_remote_state\""},{"id":"b","text":"data \"external\""},{"id":"c","text":"data \"local_file\""},{"id":"d","text":"resource \"terraform_state\""}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `terraform_remote_state` data source reads outputs from another configuration's state backend. `external` runs an external program, `local_file` reads a file, and `terraform_state` is not a resource.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/remote-state-data","label":"Terraform Docs — terraform_remote_state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$One configuration needs to consume outputs produced by ANOTHER configuration's remote state. Which data source enables this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which statement about Terraform CLI workspaces is correct?$tf$, $tf$[{"id":"a","text":"Each workspace has its own separate state, but they share the same configuration."},{"id":"b","text":"Workspaces store separate provider plugins."},{"id":"c","text":"Workspaces are the same as Git branches."},{"id":"d","text":"Workspaces require a different backend per workspace."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$CLI workspaces provide multiple named states for the same configuration/backend, enabling parallel environments. They are not Git branches and do not duplicate plugins or backends.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which statement about Terraform CLI workspaces is correct?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A resource was renamed in configuration (its address changed). Which command moves the existing object in state to the new address WITHOUT destroying it?$tf$, $tf$[{"id":"a","text":"terraform state mv OLD_ADDR NEW_ADDR"},{"id":"b","text":"terraform import NEW_ADDR"},{"id":"c","text":"terraform apply -replace=OLD_ADDR"},{"id":"d","text":"terraform refresh"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform state mv` re-keys an existing object to a new address, avoiding destroy/recreate. Import would create a duplicate-state tracking, replace recreates, and refresh only syncs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A resource was renamed in configuration (its address changed). Which command moves the existing object in state to the new address WITHOUT destroying it?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about Terraform state.$tf$, $tf$[{"id":"a","text":"State may contain sensitive values (e.g. passwords) and should be stored securely."},{"id":"b","text":"Manually hand-editing the state JSON is discouraged in favor of `terraform state` commands."},{"id":"c","text":"A remote backend can enable state locking to prevent concurrent corrupting writes."},{"id":"d","text":"State is optional and Terraform can always rebuild it for free with no risk."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$State can hold secrets, should be edited via `terraform state` (not by hand), and remote backends can lock it. State is essential — losing or carelessly rebuilding it risks orphaned/destroyed resources.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about Terraform state.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$You need to create N identical subnets where N comes from a variable. Which meta-argument is the simplest fit?$tf$, $tf$[{"id":"a","text":"count = var.subnet_count"},{"id":"b","text":"depends_on = var.subnet_count"},{"id":"c","text":"provider = var.subnet_count"},{"id":"d","text":"lifecycle = var.subnet_count"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`count` creates a fixed number of near-identical instances of a resource indexed numerically. `depends_on` orders, `provider` selects a provider, and `lifecycle` is a nested block, not a numeric multiplier.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/count","label":"Terraform Docs — count"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You need to create N identical subnets where N comes from a variable. Which meta-argument is the simplest fit?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want to prevent Terraform from accidentally destroying a critical database resource. Which configuration achieves this?$tf$, $tf$[{"id":"a","text":"A `lifecycle` block with `prevent_destroy = true` on the resource."},{"id":"b","text":"Setting `count = 0` on the resource."},{"id":"c","text":"Adding `depends_on = []`."},{"id":"d","text":"Marking the resource output as `sensitive = true`."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`lifecycle { prevent_destroy = true }` makes Terraform reject any plan that would destroy the resource. `count = 0` would actually remove it, depends_on orders dependencies, and sensitive only hides output values.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/lifecycle","label":"Terraform Docs — lifecycle"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to prevent Terraform from accidentally destroying a critical database resource. Which configuration achieves this?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which best describes a key reason organizations adopt IaC?$tf$, $tf$[{"id":"a","text":"To make every change require a manual ticket and console session."},{"id":"b","text":"To automate provisioning so environments are consistent and quickly reproducible."},{"id":"c","text":"To stop tracking what infrastructure exists."},{"id":"d","text":"To remove the need for cloud accounts."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$IaC automates provisioning for consistent, fast, reproducible environments. It does not require manual tickets, stop tracking infrastructure, or remove cloud accounts.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which best describes a key reason organizations adopt IaC?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A team scales from one environment to ten using the same parameterized configuration. Which IaC property is demonstrated?$tf$, $tf$[{"id":"a","text":"Reproducibility / repeatability."},{"id":"b","text":"Statelessness."},{"id":"c","text":"Manual provisioning."},{"id":"d","text":"Vendor lock-in."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Recreating many consistent environments from one parameterized configuration illustrates reproducibility/repeatability, a central IaC benefit.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A team scales from one environment to ten using the same parameterized configuration. Which IaC property is demonstrated?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why is "self-service" infrastructure often cited as an IaC benefit?$tf$, $tf$[{"id":"a","text":"Teams can provision approved, codified infrastructure via a repeatable pipeline instead of ticketing ops manually."},{"id":"b","text":"It removes the need for any approvals ever."},{"id":"c","text":"It deletes infrastructure automatically every night."},{"id":"d","text":"It bypasses provider APIs."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Codified, reviewed infrastructure can be offered through automated pipelines, enabling safe self-service. It does not abolish approvals or bypass provider APIs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro/use-cases","label":"Terraform Docs — Use Cases"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why is "self-service" infrastructure often cited as an IaC benefit?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Infrastructure as Code (IaC) Concepts$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL accurate statements about Infrastructure as Code.$tf$, $tf$[{"id":"a","text":"Configuration can be peer-reviewed before being applied."},{"id":"b","text":"The same code can build identical environments repeatedly."},{"id":"c","text":"Changes have a tracked history in version control."},{"id":"d","text":"IaC removes the need to ever test changes."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$IaC enables review, repeatable builds, and change history. It does not remove the need to test — previewing/validating changes is still important.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/intro","label":"Terraform Docs — Infrastructure as Code"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL accurate statements about Infrastructure as Code.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which best explains why Terraform keeps state rather than querying the cloud every time?$tf$, $tf$[{"id":"a","text":"State stores credentials so APIs are unnecessary."},{"id":"b","text":"State records the mapping of configuration to real resources and metadata, enabling accurate, performant plans."},{"id":"c","text":"State replaces the configuration files."},{"id":"d","text":"State is only used by HCP Terraform."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$State maps config to real objects and stores metadata so Terraform can compute accurate plans efficiently. It is not a credential store, a config replacement, or HCP-only.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which best explains why Terraform keeps state rather than querying the cloud every time?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$For team collaboration, which HCP Terraform capability most directly reduces the risk of conflicting concurrent changes?$tf$, $tf$[{"id":"a","text":"Managed remote state with locking and remote runs."},{"id":"b","text":"Syntax highlighting in the editor."},{"id":"c","text":"The ability to write HCL."},{"id":"d","text":"Local-only state files."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Managed remote state with locking and serialized remote runs prevents conflicting concurrent applies. HCL and editor features do not address concurrency; local state makes it worse.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/cloud","label":"Terraform Docs — HCP Terraform"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$For team collaboration, which HCP Terraform capability most directly reduces the risk of conflicting concurrent changes?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Terraform vs CloudFormation: which statement is accurate about Terraform's purpose?$tf$, $tf$[{"id":"a","text":"Terraform is multi-cloud via providers, not limited to a single vendor's services."},{"id":"b","text":"Terraform only manages AWS resources."},{"id":"c","text":"Terraform cannot manage SaaS or Kubernetes."},{"id":"d","text":"Terraform compiles to CloudFormation templates."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform is provider-driven and works across many clouds and platforms (including Kubernetes and SaaS), unlike a single-vendor tool. It does not compile to CloudFormation.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Terraform vs CloudFormation: which statement is accurate about Terraform's purpose?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Purpose of Terraform (vs other IaC)$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: A core purpose of Terraform is to provide a predictable plan/apply workflow that previews changes before they are made.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. The plan-then-apply model giving a predictable preview of changes is central to Terraform's value proposition.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: A core purpose of Terraform is to provide a predictable plan/apply workflow that previews changes before they are made.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command checks configuration syntax/consistency but does not require provider credentials or network access?$tf$, $tf$[{"id":"a","text":"terraform validate"},{"id":"b","text":"terraform apply"},{"id":"c","text":"terraform import"},{"id":"d","text":"terraform refresh"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform validate` checks syntax and internal consistency offline in an initialized directory. apply/import/refresh contact providers or modify state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/validate","label":"Terraform Docs — terraform validate"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command checks configuration syntax/consistency but does not require provider credentials or network access?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which file typically declares variables (their names, types, defaults) by convention?$tf$, $tf$[{"id":"a","text":"variables.tf"},{"id":"b","text":"terraform.tfstate"},{"id":"c","text":".terraform.lock.hcl"},{"id":"d","text":"backend.json"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$By convention `variables.tf` holds `variable` declarations (Terraform actually loads all `.tf` files). The lock file and state file serve different roles.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which file typically declares variables (their names, types, defaults) by convention?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which environment variable form sets the Terraform input variable `db_password`?$tf$, $tf$[{"id":"a","text":"TF_VAR_db_password"},{"id":"b","text":"TERRAFORM_db_password"},{"id":"c","text":"VAR_db_password"},{"id":"d","text":"TF_db_password"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Terraform reads `TF_VAR_<name>` environment variables to set input variables, e.g. `TF_VAR_db_password`. The other prefixes are not recognized.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which environment variable form sets the Terraform input variable `db_password`?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does `terraform fmt -recursive` do?$tf$, $tf$[{"id":"a","text":"Formats `.tf` files in the current directory and all subdirectories."},{"id":"b","text":"Validates all modules recursively."},{"id":"c","text":"Destroys nested resources."},{"id":"d","text":"Initializes every submodule's backend."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform fmt -recursive` reformats configuration files in the current directory and all subdirectories. It does not validate, destroy, or init.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/fmt","label":"Terraform Docs — terraform fmt"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does `terraform fmt -recursive` do?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which block exposes a value (like an instance IP) for users or other configurations to read?$tf$, $tf$[{"id":"a","text":"output"},{"id":"b","text":"variable"},{"id":"c","text":"provider"},{"id":"d","text":"backend"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$An `output` block surfaces a value after apply (and for `terraform output`/remote_state). variables are inputs, provider configures the platform, backend stores state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which block exposes a value (like an instance IP) for users or other configurations to read?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about provider version constraints.$tf$, $tf$[{"id":"a","text":"`= 3.1.0` pins an exact version."},{"id":"b","text":"`>= 3.1.0` allows that version or newer."},{"id":"c","text":"`~> 3.1` allows 3.x but not 4.0."},{"id":"d","text":"Version constraints are stored in the state file."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Exact, lower-bound, and pessimistic constraints behave as described. Version constraints live in configuration (`required_providers`) and selections in the lock file — not in state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/settings","label":"Terraform Docs — Terraform Settings"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about provider version constraints.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Fundamentals$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: `terraform validate` requires the working directory to have been initialized first with `terraform init`.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. `validate` needs provider schemas/modules available, so the directory must be initialized via `terraform init` first.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/validate","label":"Terraform Docs — terraform validate"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: `terraform validate` requires the working directory to have been initialized first with `terraform init`.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What does a `-` (minus) prefix on a resource in plan output indicate?$tf$, $tf$[{"id":"a","text":"It will be created."},{"id":"b","text":"It will be destroyed."},{"id":"c","text":"It will be updated in place."},{"id":"d","text":"It is unchanged."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`-` means the resource will be destroyed; `+` create, `~` update in place, `-/+` replace.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does a `-` (minus) prefix on a resource in plan output indicate?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command would you add to a CI pipeline to fail the build if files are not canonically formatted?$tf$, $tf$[{"id":"a","text":"terraform fmt -check"},{"id":"b","text":"terraform fmt -write"},{"id":"c","text":"terraform validate -fmt"},{"id":"d","text":"terraform plan -fmt"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform fmt -check` exits non-zero if any file is not properly formatted, without rewriting — ideal for CI gating. The other forms do not perform this check.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/fmt","label":"Terraform Docs — terraform fmt"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command would you add to a CI pipeline to fail the build if files are not canonically formatted?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You need to recreate one resource on the next apply because the provider cannot detect a needed change. Current recommended command?$tf$, $tf$[{"id":"a","text":"terraform apply -replace=\"aws_db_instance.main\""},{"id":"b","text":"terraform taint aws_db_instance.main"},{"id":"c","text":"terraform refresh"},{"id":"d","text":"terraform fmt"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform apply -replace=ADDR` is the modern recommended way to force replacement of a specific resource; `terraform taint` is deprecated. refresh/fmt do not recreate.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/taint","label":"Terraform Docs — terraform taint"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You need to recreate one resource on the next apply because the provider cannot detect a needed change. Current recommended command?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$In the core workflow, which step actually changes real infrastructure?$tf$, $tf$[{"id":"a","text":"Write"},{"id":"b","text":"Plan"},{"id":"c","text":"Apply"},{"id":"d","text":"Validate"}]$tf$::jsonb, $tf$["c"]$tf$::jsonb, $tf$Apply executes the planned changes against real infrastructure. Write authors config, Plan previews, and Validate checks syntax.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/apply","label":"Terraform Docs — terraform apply"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$In the core workflow, which step actually changes real infrastructure?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Why is `-target` documented as something to use sparingly?$tf$, $tf$[{"id":"a","text":"It permanently disables state."},{"id":"b","text":"It can produce a partial apply that diverges from full configuration, so it is for exceptional cases."},{"id":"c","text":"It deletes the lock file."},{"id":"d","text":"It always destroys all resources."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$`-target` applies only a subset, which can leave configuration and state inconsistent if overused; it is meant for exceptional recovery situations, not routine use.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Why is `-target` documented as something to use sparingly?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You changed the `backend` block. Running `terraform plan` immediately gives a backend initialization error. What is the fix?$tf$, $tf$[{"id":"a","text":"Re-run `terraform init` to migrate/reconfigure the backend."},{"id":"b","text":"Run `terraform fmt`."},{"id":"c","text":"Delete `.terraform.lock.hcl`."},{"id":"d","text":"Run `terraform output`."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Backend changes require `terraform init` (often with `-migrate-state` or `-reconfigure`) before plan/apply works again. fmt/output and deleting the lock file do not resolve it.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You changed the `backend` block. Running `terraform plan` immediately gives a backend initialization error. What is the fix?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$The Terraform Workflow$tf$, 2, $tf$MULTI$tf$::"QType", $tf$Select ALL commands that are read-only with respect to real infrastructure.$tf$, $tf$[{"id":"a","text":"terraform plan"},{"id":"b","text":"terraform validate"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform destroy"}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$plan previews, validate checks syntax, and fmt formats files — none change real infrastructure. destroy removes resources.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/validate","label":"Terraform Docs — terraform validate"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/fmt","label":"Terraform Docs — terraform fmt"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL commands that are read-only with respect to real infrastructure.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$A module on the public registry is referenced without a host prefix. Which registry is implied?$tf$, $tf$[{"id":"a","text":"The public Terraform Registry (registry.terraform.io)."},{"id":"b","text":"A private GitLab instance."},{"id":"c","text":"The local filesystem."},{"id":"d","text":"An S3 bucket."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A bare `<namespace>/<name>/<provider>` address resolves to the public Terraform Registry by default; other hosts need an explicit host prefix.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A module on the public registry is referenced without a host prefix. Which registry is implied?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$Which keyword/block calls a child module from the root configuration?$tf$, $tf$[{"id":"a","text":"module"},{"id":"b","text":"resource"},{"id":"c","text":"provider"},{"id":"d","text":"data"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$A `module` block instantiates a child module (with `source` and inputs). resource/data/provider declare other constructs.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which keyword/block calls a child module from the root configuration?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which is true about outputs declared in a child module?$tf$, $tf$[{"id":"a","text":"They are only consumable by the calling configuration via `module.<name>.<output>`."},{"id":"b","text":"They are global variables anywhere in the project."},{"id":"c","text":"They are written to the provider plugin."},{"id":"d","text":"They cannot reference the module's own resources."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Child module outputs are exposed to the caller as `module.<name>.<output>` and typically reference the module's resources. They are not global or written to plugins.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/values/outputs","label":"Terraform Docs — Output Values"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which is true about outputs declared in a child module?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A module needs an aliased provider configured in the root. How is it passed to the child module?$tf$, $tf$[{"id":"a","text":"Via the `providers = { aws = aws.west }` argument in the `module` block."},{"id":"b","text":"By redeclaring the provider inside the child automatically."},{"id":"c","text":"Through an `output` block."},{"id":"d","text":"It is impossible to pass aliased providers to modules."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The `providers` meta-argument on a `module` block maps the caller's (possibly aliased) provider configurations into the child module. Outputs are unrelated to provider passing.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/providers","label":"Terraform Docs — Providers"},{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A module needs an aliased provider configured in the root. How is it passed to the child module?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$What happens if you change a registry module's pinned `version` and run plan without re-initializing?$tf$, $tf$[{"id":"a","text":"Terraform errors/asks you to run init because the new module version is not installed."},{"id":"b","text":"Terraform silently downloads it during plan."},{"id":"c","text":"Terraform ignores the version change."},{"id":"d","text":"Terraform destroys all resources."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Module version/source changes require `terraform init` to install the new version before planning; Terraform will not silently fetch it during plan.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/init","label":"Terraform Docs — terraform init"},{"url":"https://developer.hashicorp.com/terraform/language/modules/syntax","label":"Terraform Docs — Module Registry"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What happens if you change a registry module's pinned `version` and run plan without re-initializing?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 3, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: A child module cannot directly read the root module's variables; values must be passed in explicitly as module arguments.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Modules are encapsulated — a child only receives values its caller explicitly passes as input arguments; it cannot reach into the root's variables.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/values/variables","label":"Terraform Docs — Input Variables"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: A child module cannot directly read the root module's variables; values must be passed in explicitly as module arguments.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Terraform Modules$tf$, 2, $tf$MULTI$tf$::"QType", $tf$Select ALL valid `module` block arguments/meta-arguments.$tf$, $tf$[{"id":"a","text":"source"},{"id":"b","text":"version"},{"id":"c","text":"for_each"},{"id":"d","text":"backend"}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$`source`, `version`, and meta-arguments like `for_each`/`count`/`depends_on`/`providers` are valid on module blocks. `backend` is configured in the `terraform` block, not on a module.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/modules","label":"Terraform Docs — Modules"},{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL valid `module` block arguments/meta-arguments.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command associates an EXISTING manually-created S3 bucket with `aws_s3_bucket.logs` in state?$tf$, $tf$[{"id":"a","text":"terraform import aws_s3_bucket.logs my-bucket-name"},{"id":"b","text":"terraform apply -import"},{"id":"c","text":"terraform state add aws_s3_bucket.logs"},{"id":"d","text":"terraform refresh aws_s3_bucket.logs"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform import <address> <id>` binds an existing object to a resource address in state. There is no `state add` subcommand, and refresh/apply do not import.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/import","label":"Terraform Docs — terraform import"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command associates an EXISTING manually-created S3 bucket with `aws_s3_bucket.logs` in state?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want to evaluate `cidrsubnet("10.0.0.0/16", 8, 2)` quickly without applying anything. Best tool?$tf$, $tf$[{"id":"a","text":"terraform console"},{"id":"b","text":"terraform apply"},{"id":"c","text":"terraform import"},{"id":"d","text":"terraform fmt"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform console` is an interactive REPL perfect for testing function expressions like `cidrsubnet(...)` without changing infrastructure.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/console","label":"Terraform Docs — terraform console"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want to evaluate `cidrsubnet("10.0.0.0/16", 8, 2)` quickly without applying anything. Best tool?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command synchronizes state with real resources without proposing or making infrastructure changes (modern form)?$tf$, $tf$[{"id":"a","text":"terraform apply -refresh-only"},{"id":"b","text":"terraform validate"},{"id":"c","text":"terraform fmt"},{"id":"d","text":"terraform import"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform apply -refresh-only` updates state to match real resources without altering infrastructure (the modern replacement for standalone `terraform refresh`).$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"},{"url":"https://developer.hashicorp.com/terraform/cli/commands/plan","label":"Terraform Docs — terraform plan"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command synchronizes state with real resources without proposing or making infrastructure changes (modern form)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Use Terraform Outside the Core Workflow$tf$, 3, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: `terraform_remote_state` only exposes the OTHER configuration's declared outputs, not its full resource attributes.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. The `terraform_remote_state` data source surfaces only the root outputs the other configuration explicitly exports, not arbitrary internal resource attributes.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/remote-state-data","label":"Terraform Docs — terraform_remote_state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: `terraform_remote_state` only exposes the OTHER configuration's declared outputs, not its full resource attributes.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 1, $tf$SINGLE$tf$::"QType", $tf$What does Terraform state primarily track?$tf$, $tf$[{"id":"a","text":"The mapping between configuration resources and real infrastructure objects, plus metadata."},{"id":"b","text":"The Terraform CLI download history."},{"id":"c","text":"The user's shell command history."},{"id":"d","text":"Provider plugin source code."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$State maps declared resources to real-world objects and stores metadata Terraform needs for planning. It is not a command history or plugin source store.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$What does Terraform state primarily track?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which command deletes the workspace named "temp" (must not be the current/only one)?$tf$, $tf$[{"id":"a","text":"terraform workspace delete temp"},{"id":"b","text":"terraform workspace rm temp"},{"id":"c","text":"terraform delete workspace temp"},{"id":"d","text":"terraform workspace drop temp"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform workspace delete <name>` removes a workspace (you cannot delete the currently selected or default workspace). The other forms are invalid.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/workspaces","label":"Terraform Docs — Workspaces"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which command deletes the workspace named "temp" (must not be the current/only one)?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$A resource block was renamed from `aws_instance.app` to `aws_instance.web`. Without intervention, what does plan show?$tf$, $tf$[{"id":"a","text":"A no-op."},{"id":"b","text":"Destroy of `aws_instance.app` and create of `aws_instance.web` (unless you `state mv` or use a `moved` block)."},{"id":"c","text":"Only an in-place update."},{"id":"d","text":"An import prompt."}]$tf$::jsonb, $tf$["b"]$tf$::jsonb, $tf$Renaming an address makes Terraform see the old one as removed and the new one as added (destroy+create). `terraform state mv` or a `moved` block preserves the object.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$A resource block was renamed from `aws_instance.app` to `aws_instance.web`. Without intervention, what does plan show?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which is a valid reason to use a remote backend instead of local state for a team?$tf$, $tf$[{"id":"a","text":"Shared, centralized state with locking to prevent conflicting writes."},{"id":"b","text":"It removes the need to write configuration."},{"id":"c","text":"It makes provider plugins unnecessary."},{"id":"d","text":"It disables the plan step."}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$Remote backends provide shared state plus locking so teams do not corrupt state with concurrent applies. They do not remove config, providers, or planning.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"},{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which is a valid reason to use a remote backend instead of local state for a team?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want Terraform to stop managing a resource but keep the real object alive. Which command?$tf$, $tf$[{"id":"a","text":"terraform state rm aws_instance.legacy"},{"id":"b","text":"terraform destroy -target=aws_instance.legacy"},{"id":"c","text":"terraform apply -replace=aws_instance.legacy"},{"id":"d","text":"terraform taint aws_instance.legacy"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`terraform state rm` removes the resource from state so Terraform no longer manages it while leaving the real object intact. destroy deletes it; replace/taint recreate it.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want Terraform to stop managing a resource but keep the real object alive. Which command?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: Hand-editing the raw state JSON is discouraged; the supported approach is the `terraform state` subcommands.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Manual edits risk corrupting state; HashiCorp recommends the `terraform state` family (mv/rm/show/list) for safe modifications.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/cli/commands/state","label":"Terraform Docs — terraform state"},{"url":"https://developer.hashicorp.com/terraform/language/state","label":"Terraform Docs — State"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: Hand-editing the raw state JSON is discouraged; the supported approach is the `terraform state` subcommands.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Implement and Maintain State$tf$, 3, $tf$MULTI$tf$::"QType", $tf$Select ALL true statements about remote backends and locking.$tf$, $tf$[{"id":"a","text":"Some backends support automatic state locking during writes."},{"id":"b","text":"Locking helps prevent state corruption from concurrent operations."},{"id":"c","text":"Not all backends support locking."},{"id":"d","text":"Locking eliminates the need for state entirely."}]$tf$::jsonb, $tf$["a","b","c"]$tf$::jsonb, $tf$Many backends lock state during writes to prevent concurrent corruption, but not all backends support locking. Locking does not eliminate the need for state.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/state/locking","label":"Terraform Docs — State Locking"},{"url":"https://developer.hashicorp.com/terraform/language/backend","label":"Terraform Docs — Backends"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Select ALL true statements about remote backends and locking.$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which meta-argument creates resource instances keyed by each element of a set or map?$tf$, $tf$[{"id":"a","text":"for_each"},{"id":"b","text":"count"},{"id":"c","text":"lifecycle"},{"id":"d","text":"provider"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`for_each` instantiates one resource per element of a map/set, keyed by the element key (stable across changes). `count` uses numeric indexes; lifecycle/provider serve other roles.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/for_each","label":"Terraform Docs — for_each"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which meta-argument creates resource instances keyed by each element of a set or map?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$You want Terraform to create a new replacement resource BEFORE destroying the old one to avoid downtime. Which lifecycle setting?$tf$, $tf$[{"id":"a","text":"create_before_destroy = true"},{"id":"b","text":"prevent_destroy = true"},{"id":"c","text":"ignore_changes = all"},{"id":"d","text":"replace_triggered_by = []"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`lifecycle { create_before_destroy = true }` provisions the replacement before destroying the original, minimizing downtime. The other settings address deletion protection, drift ignoring, and forced replacement triggers.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/lifecycle","label":"Terraform Docs — lifecycle"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$You want Terraform to create a new replacement resource BEFORE destroying the old one to avoid downtime. Which lifecycle setting?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$SINGLE$tf$::"QType", $tf$Which lifecycle setting tells Terraform to ignore external changes to specified attributes during plan?$tf$, $tf$[{"id":"a","text":"ignore_changes"},{"id":"b","text":"prevent_destroy"},{"id":"c","text":"create_before_destroy"},{"id":"d","text":"depends_on"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$`lifecycle { ignore_changes = [..] }` makes Terraform disregard drift on listed attributes so it does not try to revert them. The others control destruction order/protection or dependencies.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/lifecycle","label":"Terraform Docs — lifecycle"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which lifecycle setting tells Terraform to ignore external changes to specified attributes during plan?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 3, $tf$SINGLE$tf$::"QType", $tf$Which function reads and returns the contents of a file at plan/apply time?$tf$, $tf$[{"id":"a","text":"file(\"script.sh\")"},{"id":"b","text":"read(\"script.sh\")"},{"id":"c","text":"load(\"script.sh\")"},{"id":"d","text":"open(\"script.sh\")"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$The built-in `file(path)` function returns the file's contents as a string. `read`/`load`/`open` are not Terraform functions.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/functions","label":"Terraform Docs — Built-in Functions"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$Which function reads and returns the contents of a file at plan/apply time?$tf$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $tf$Read, Generate, and Modify Configuration$tf$, 2, $tf$TRUE_FALSE$tf$::"QType", $tf$True or False: `depends_on` should be used for explicit ordering only when Terraform cannot infer a dependency automatically from references.$tf$, $tf$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$tf$::jsonb, $tf$["a"]$tf$::jsonb, $tf$True. Terraform infers most dependencies from expression references; `depends_on` is for the rare cases where an implicit dependency cannot be detected.$tf$, $tf$[{"url":"https://developer.hashicorp.com/terraform/language/meta-arguments/depends_on","label":"Terraform Docs — Meta-Arguments"},{"url":"https://developer.hashicorp.com/terraform/language/resources/behavior","label":"Terraform Docs — Resource Dependencies"}]$tf$::jsonb, $tf$PUBLISHED$tf$::"QStatus", $tf$manual:terraform-seed$tf$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $tf$TFA003-P3$tf$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $tf$True or False: `depends_on` should be used for explicit ordering only when Terraform cannot infer a dependency automatically from references.$tf$);
